1	import { Request, Response, NextFunction } from 'express';
2	import { Error as MongooseError } from 'mongoose';
3	import { AppError } from '../utils/AppError';
4	
5	interface CustomError extends Error {
6	  statusCode?: number;
7	  code?: number;
8	  keyValue?: any;
9	  errors?: any;
10	}
11	
12	export const errorHandler = (
13	  err: CustomError,
14	  _req: Request,
15	  res: Response,
16	  _next: NextFunction
17	): void => {
18	  if (process.env.NODE_ENV === 'development') {
19	    console.error('❌ Error:', err.message);
20	  }
21	
22	  // AppError — наши бизнес-ошибки, пробрасываем как есть
23	  if (err instanceof AppError) {
24	    res.status(err.statusCode).json({ success: false, message: err.message });
25	    return;
26	  }
27	
28	  let statusCode = err.statusCode || 500;
29	  let message = err.message || 'Internal Server Error';
30	  let errors: any[] = [];
31	
32	  // Mongoose Validation Error
33	  if (err instanceof MongooseError.ValidationError) {
34	    statusCode = 400;
35	    message = 'Validation Error';
36	    errors = Object.values(err.errors).map((error: any) => ({
37	      field: error.path,
38	      message: error.message
39	    }));
40	  }
41	
42	  // Mongoose Cast Error (неверный формат ObjectId)
43	  if (err.name === 'CastError') {
44	    statusCode = 400;
45	    message = 'Invalid ID format';
46	  }
47	
48	  // Mongoose Duplicate Key Error
49	  if (err.code === 11000) {
50	    statusCode = 400;
51	    message = 'Duplicate field value';
52	    const field = Object.keys(err.keyValue || {})[0];
53	    errors = [{
54	      field,
55	      message: `${field} already exists`
56	    }];
57	  }
58	
59	  // JWT Errors (обрабатываются в auth middleware, но на всякий случай)
60	  if (err.name === 'JsonWebTokenError') {
61	    statusCode = 401;
62	    message = 'Invalid token';
63	  }
64	
65	  if (err.name === 'TokenExpiredError') {
66	    statusCode = 401;
67	    message = 'Token expired';
68	  }
69	
70	  res.status(statusCode).json({
71	    success: false,
72	    message,
73	    ...(errors.length > 0 && { errors }),
74	    ...(process.env.NODE_ENV === 'development' && { stack: err.stack })
75	  });
76	};
